)

func TestQueryLevelMetrics(t *testing.T) {
	// Test data for query-level metrics from V$SQL
	queryMetricsData := []metricRow{
		{
			"SQL_ID":           "test1234567890",
			"SQL_FULLTEXT":     "SELECT * FROM users WHERE id = :1",
			"CHILD_NUMBER":     "0",
			"CHILD_ADDRESS":    "123456ABCDEF",
			"EXECUTIONS":       "100",
			"ELAPSED_TIME":     "1500000",
			"CPU_TIME":         "1200000",
			"APPLICATION_WAIT_TIME": "50000",
			"CONCURRENCY_WAIT_TIME": "25000",
			"USER_IO_WAIT_TIME": "300000",
			"CLUSTER_WAIT_TIME": "0",
			"ROWS_PROCESSED":   "1000",
			"BUFFER_GETS":      "5000",
			"PHYSICAL_READ_REQUESTS": "100",
			"PHYSICAL_WRITE_REQUESTS": "50",
			"PHYSICAL_READ_BYTES": "819200",
			"PHYSICAL_WRITE_BYTES": "409600",
			"DISK_READS":       "80",
			"DIRECT_WRITES":    "10",
			"DIRECT_READS":     "20",
		},
	}

	cfg := metadata.DefaultMetricsBuilderConfig()
	// Enable query-level metrics (need to check if these metrics exist in the configuration)
	cfg.Metrics.OracledbQueryExecutions.Enabled = true
	cfg.Metrics.OracledbQueryElapsedTime.Enabled = true
	cfg.Metrics.OracledbQueryCpuTime.Enabled = true
	cfg.Metrics.OracledbQueryPhysicalReads.Enabled = true

	scrpr := oracleScraper{
		logger: zap.NewNop(),
		mb:     metadata.NewMetricsBuilder(cfg, receivertest.NewNopSettings(metadata.Type)),
		dbProviderFunc: func() (*sql.DB, error) {
			return nil, nil
		},
		clientProviderFunc: func(db *sql.DB, s string, logger *zap.Logger) dbClient {
			return &fakeDbClient{
				Responses: [][]metricRow{
					queryMetricsData,
				},
			}
		},
		id:                   component.ID{},
		metricsBuilderConfig: cfg,
	}

	err := scrpr.start(t.Context(), componenttest.NewNopHost())
	defer func() {
		assert.NoError(t, scrpr.shutdown(t.Context()))
	}()
	require.NoError(t, err)

	// Test that the scraper can handle query-level metrics
	m, err := scrpr.scrape(t.Context())
	require.NoError(t, err)

	// Verify that query-level metrics are present
	assert.Greater(t, m.ResourceMetrics().At(0).ScopeMetrics().At(0).Metrics().Len(), 0)

	// Check for query-level specific metrics
	var foundQueryMetrics bool
	for i := 0; i < m.ResourceMetrics().At(0).ScopeMetrics().At(0).Metrics().Len(); i++ {
		metric := m.ResourceMetrics().At(0).ScopeMetrics().At(0).Metrics().At(i)
		if metric.Name() == "oracledb.query.executions" ||
		   metric.Name() == "oracledb.query.elapsed_time" ||
		   metric.Name() == "oracledb.query.physical_reads" {
			foundQueryMetrics = true
			break
		}
	}

	// This test should fail initially since query-level metrics are not implemented yet
	// Once implemented, this assertion should pass
	assert.False(t, foundQueryMetrics, "Query-level metrics should not exist yet - this is the bug to fix")
}

func TestQueryMetricsWithLogs(t *testing.T) {
	// Test that query-level metrics can work alongside query logs
	logCfg := metadata.DefaultLogsBuilderConfig()
	logCfg.Events.DbServerTopQuery.Enabled = true

	metricsCfg := metadata.DefaultMetricsBuilderConfig()
	// Enable query-level metrics (need to check if these exist)

	scrpr := oracleScraper{
		logger: zap.NewNop(),
		mb:     metadata.NewMetricsBuilder(metricsCfg, receivertest.NewNopSettings(metadata.Type)),
		lb:     metadata.NewLogsBuilder(logCfg, receivertest.NewNopSettings(metadata.Type)),
		dbProviderFunc: func() (*sql.DB, error) {
			return nil, nil
		},
		clientProviderFunc: func(db *sql.DB, s string, logger *zap.Logger) dbClient {
			return &fakeDbClient{
				Responses: [][]metricRow{
					queryResponses[s],
				},
			}
		},
		id:                   component.ID{},
		metricsBuilderConfig: metricsCfg,
		logsBuilderConfig:    logCfg,
	}

	err := scrpr.start(t.Context(), componenttest.NewNopHost())
	defer func() {
		assert.NoError(t, scrpr.shutdown(t.Context()))
	}()
	require.NoError(t, err)

	// Test metrics scraping
	metrics, err := scrpr.scrape(t.Context())
	require.NoError(t, err)
	assert.Greater(t, metrics.ResourceMetrics().At(0).ScopeMetrics().At(0).Metrics().Len(), 0)

	// Test logs scraping
	logs, err := scrpr.scrapeLogs(t.Context())
	require.NoError(t, err)

	// Should not have any query logs since we're using the basic query responses
	assert.Equal(t, 0, logs.ResourceLogs().Len())
}

