// Copyright The OpenTelemetry Authors
// SPDX-License-Identifier: Apache-2.0

package oracledbreceiver

import (
	"context"
	"fmt"
	"strconv"

	"go.opentelemetry.io/collector/pdata/pcommon"
	"go.uber.org/zap"

	"github.com/open-telemetry/opentelemetry-collector-contrib/receiver/oracledbreceiver/internal/metadata"
)

// query_level_constants.go
const (
	queryLevelPrefix             = "oracledb.query."
	queryExecutionsMetricKey     = "oracledb.query.executions"
	queryElapsedTimeMetricKey    = "oracledb.query.elapsed_time"
	queryCpuTimeMetricKey        = "oracledb.query.cpu_time"
	queryApplicationWaitTimeKey  = "oracledb.query.application_wait_time"
	queryConcurrencyWaitTimeKey  = "oracledb.query.concurrency_wait_time"
	queryUserIoWaitTimeKey       = "oracledb.query.user_io_wait_time"
	queryClusterWaitTimeKey      = "oracledb.query.cluster_wait_time"
	queryRowsProcessedKey        = "oracledb.query.rows_processed"
	queryBufferGetsKey           = "oracledb.query.buffer_gets"
	queryPhysicalReadRequestsKey = "oracledb.query.physical_read_requests"
	queryPhysicalReadBytesKey    = "oracledb.query.physical_read_bytes"
	queryPhysicalWriteRequestsKey = "oracledb.query.physical_write_requests"
	queryPhysicalWriteBytesKey   = "oracledb.query.physical_write_bytes"
	queryDiskReadsKey            = "oracledb.query.disk_reads"
	queryDirectReadsKey          = "oracledb.query.direct_reads"
	queryDirectWritesKey         = "oracledb.query.direct_writes"
	queryLastActiveTimeWindowSec = 300 // 5 minutes window for active queries
)

// QueryLevelMetricsConfig configuration for query-level metrics collection
type QueryLevelMetricsConfig struct {
	Enabled                bool `mapstructure:"enabled"`
	MaxQueriesToCollect    int  `mapstructure:"max_queries_to_collect"`
	CollectionIntervalSecs int  `mapstructure:"collection_interval_seconds"`
}

// queryLevelMetricCache manages delta calculations for query-level metrics
type queryLevelMetricCache struct {
	cache *lru.Cache[string, map[string]int64] // sql_id:child_number -> metric values
	logger *zap.Logger
}

func newQueryLevelMetricCache(size int, logger *zap.Logger) (*queryLevelMetricCache, error) {
	cache, err := lru.New[string, map[string]int64](size)
	if err != nil {
		return nil, fmt.Errorf("failed to create query-level metric cache: %w", err)
	}
	return &queryLevelMetricCache{
		cache:  cache,
		logger: logger,
	}, nil
}

func (c *queryLevelMetricCache) getDelta(currentValues map[string]int64, cacheKey string) (map[string]int64, bool) {
	previousValues, exists := c.cache.Get(cacheKey)
	if !exists {
		// No previous values, store current for next time
		c.cache.Add(cacheKey, currentValues)
		return nil, false
	}

	deltaValues := make(map[string]int64)
	for metricName, currentValue := range currentValues {
		previousValue := previousValues[metricName]
		delta := currentValue - previousValue
		if delta < 0 {
			// Query may have been purged from shared pool, ignore negative delta
			return nil, false
		}
		deltaValues[metricName] = delta
	}

	// Update cache with current values
	c.cache.Add(cacheKey, currentValues)
	return deltaValues, true
}

// collectQueryLevelMetrics collects query-level performance metrics from V$SQL
func (s *oracleScraper) collectQueryLevelMetrics(ctx context.Context) ([]queryMetricData, error) {
	if !s.metricsBuilderConfig.Metrics.OracledbQueryExecutions.Enabled &&
		!s.metricsBuilderConfig.Metrics.OracledbQueryElapsedTime.Enabled {
		// Query-level metrics are disabled
		return nil, nil
	}

	timestampStrings := []string{
		pcommon.NewTimestampFromTime(time.Now()).Format(dbTimeReferenceFormat),
		fmt.Sprintf("%d", queryLastActiveTimeWindowSec),
	}

	// Fetch query metrics from V$SQL
	s.oracleQueryMetricsClient = s.clientProviderFunc(s.db, oracleQueryMetricsSQL, s.logger)
	rows, err := s.oracleQueryMetricsClient.metricRows(ctx, append(timestampStrings, "100")...) // Limit to 100 queries
	if err != nil {
		return nil, fmt.Errorf("error executing oracleQueryMetricsSQL: %w", err)
	}

	if len(rows) == 0 {
		return nil, nil
	}

	var results []queryMetricData
	for _, row := range rows {
		sqlID := row[sqlIDAttr]
		childNumber := row[childNumberAttr]
		cacheKey := fmt.Sprintf("%s:%s", sqlID, childNumber)

		// Extract current metric values
		currentValues := s.extractQueryMetricValues(row)

		// Calculate delta from previous collection
		deltaValues, hasValidDelta := s.queryLevelMetricCache.getDelta(currentValues, cacheKey)
		if !hasValidDelta {
			continue
		}

		// Check if we have any positive deltas to report
		hasPositiveValue := false
		for _, delta := range deltaValues {
			if delta > 0 {
				hasPositiveValue = true
				break
			}
		}

		if hasPositiveValue {
			results = append(results, queryMetricData{
				SQLID:       sqlID,
				ChildNumber: childNumber,
				QueryText:   row[sqlTextAttr],
				Values:      deltaValues,
			})
		}
	}

	s.logger.Debug("Collected query-level metrics", zap.Int("query_count", len(results)))
	return results, nil
}

// extractQueryMetricValues extracts metric values from query result row
func (s *oracleScraper) extractQueryMetricValues(row metricRow) map[string]int64 {
	values := make(map[string]int64)

	metricMappings := map[string]string{
		"EXECUTIONS":             queryExecutionMetric,
		"ELAPSED_TIME":           elapsedTimeMetric,
		"CPU_TIME":               cpuTimeMetric,
		"APPLICATION_WAIT_TIME":  applicationWaitTimeMetric,
		"CONCURRENCY_WAIT_TIME":  concurrencyWaitTimeMetric,
		"USER_IO_WAIT_TIME":      userIoWaitTimeMetric,
		"CLUSTER_WAIT_TIME":      clusterWaitTimeMetric,
		"ROWS_PROCESSED":         rowsProcessedMetric,
		"BUFFER_GETS":            bufferGetsMetric,
		"PHYSICAL_READ_REQUESTS": physicalReadRequestsMetric,
		"PHYSICAL_READ_BYTES":    physicalReadBytesMetric,
		"PHYSICAL_WRITE_REQUESTS": physicalWriteRequestsMetric,
		"PHYSICAL_WRITE_BYTES":   physicalWriteBytesMetric,
		"DISK_READS":             queryDiskReadsMetric,
		"DIRECT_READS":           queryDirectReadsMetric,
		"DIRECT_WRITES":          queryDirectWritesMetric,
	}

	for dbColumn, metricKey := range metricMappings {
		if valueStr, exists := row[dbColumn]; exists && valueStr != "" {
			if value, err := strconv.ParseInt(valueStr, 10, 64); err == nil {
				values[metricKey] = value
			} else {
				s.logger.Debug("Failed to parse query metric value",
					zap.String("column", dbColumn),
					zap.String("value", valueStr),
					zap.Error(err))
			}
		}
	}

	return values
}

// queryMetricData represents collected metrics for a specific query
type queryMetricData struct {
	SQLID       string
	ChildNumber string
	QueryText   string
	Values      map[string]int64 // metricKey -> delta value
}

// recordQueryLevelMetrics records query-level metrics using the metrics builder
func (s *oracleScraper) recordQueryLevelMetrics(timestamp pcommon.Timestamp, metrics []queryMetricData) {
	for _, queryMetric := range metrics {
		fmt.Printf("Recording query metrics for SQL_ID: %s, Child: %s\n", queryMetric.SQLID, queryMetric.ChildNumber)

		// Create resource with query identification attributes
		rb := s.mb.NewResourceBuilder()
		rb.SetOracledbInstanceName(s.instanceName)
		rb.SetHostName(s.hostName)
		rb.Attributes().PutStr("oracledb.sql_id", queryMetric.SQLID)
		rb.Attributes().PutStr("oracledb.child_number", queryMetric.ChildNumber)

		// Record individual metrics based on configuration
		for metricKey, deltaValue := range queryMetric.Values {
			switch metricKey {
			case queryExecutionMetric:
				s.mb.RecordOracledbQueryExecutionsDataPoint(timestamp, deltaValue)
			case elapsedTimeMetric:
				s.mb.RecordOracledbQueryElapsedTimeDataPoint(timestamp, float64(deltaValue)/1e6) // Convert microseconds to seconds
			case cpuTimeMetric:
				s.mb.RecordOracledbQueryCpuTimeDataPoint(timestamp, float64(deltaValue)/1e6)
			case applicationWaitTimeMetric:
				s.mb.RecordOracledbQueryApplicationWaitTimeDataPoint(timestamp, float64(deltaValue)/1e6)
			case concurrencyWaitTimeMetric:
				s.mb.RecordOracledbQueryConcurrencyWaitTimeDataPoint(timestamp, float64(deltaValue)/1e6)
			case userIoWaitTimeMetric:
				s.mb.RecordOracledbQueryUserIoWaitTimeDataPoint(timestamp, float64(deltaValue)/1e6)
			case clusterWaitTimeMetric:
				s.mb.RecordOracledbQueryClusterWaitTimeDataPoint(timestamp, float64(deltaValue)/1e6)
			case rowsProcessedMetric:
				s.mb.RecordOracledbQueryRowsProcessedDataPoint(timestamp, deltaValue)
			case bufferGetsMetric:
				s.mb.RecordOracledbQueryBufferGetsDataPoint(timestamp, deltaValue)
			case physicalReadRequestsMetric:
				s.mb.RecordOracledbQueryPhysicalReadRequestsDataPoint(timestamp, deltaValue)
			case physicalReadBytesMetric:
				s.mb.RecordOracledbQueryPhysicalReadBytesDataPoint(timestamp, deltaValue)
			case physicalWriteRequestsMetric:
				s.mb.RecordOracledbQueryPhysicalWriteRequestsDataPoint(timestamp, deltaValue)
			case physicalWriteBytesMetric:
				s.mb.RecordOracledbQueryPhysicalWriteBytesDataPoint(timestamp, deltaValue)
			case queryDiskReadsMetric:
				s.mb.RecordOracledbQueryDiskReadsDataPoint(timestamp, deltaValue)
			case queryDirectReadsMetric:
				s.mb.RecordOracledbQueryDirectReadsDataPoint(timestamp, deltaValue)
			case queryDirectWritesMetric:
				s.mb.RecordOracledbQueryDirectWritesDataPoint(timestamp, deltaValue)
			}
		}
	}
}

// updateScraperWithQueryLevelCache ensures the scraper has query-level metric cache
func (s *oracleScraper) ensureQueryLevelMetricCache() {
	if s.queryLevelMetricCache == nil {
		cache, err := newQueryLevelMetricCache(1000, s.logger)
		if err != nil {
			s.logger.Error("Failed to initialize query-level metric cache", zap.Error(err))
			return
		}
		s.queryLevelMetricCache = cache
	}
}

